<script lang="ts">
	import { ArrowLeft, ArrowUpRight, RefreshCw, Sheet, CircleAlert, ExternalLink } from 'lucide-svelte';
	let { data } = $props();
	let active = $state('Customers');
	const selected = $derived(data.sheets.find((sheet) => sheet.name === active) ?? data.sheets[0]);
	const isPhoneColumn = (column: string) => /phone|mobile|whatsapp/i.test(column);
</script>

<svelte:head><title>Sheets data — Anjana Creations</title></svelte:head>

<div class="sheet-heading">
	<div class="heading-copy"><a href="/settings"><ArrowLeft size={14}/> Back to settings</a><span class="eyebrow"><Sheet size={13}/> Data workspace</span><h1>Google Sheets data</h1><p>Browse the live tables behind your customers, orders, editors, billing, and studio activity.</p></div>
	<div class="sheet-actions"><a class="secondary open-sheet" href={data.sheetUrl} target="_blank" rel="noopener noreferrer"><ExternalLink size={13}/> Open Google Sheet</a><button class="secondary" onclick={() => location.reload()}><RefreshCw size={13}/> Refresh</button></div>
</div>

<div class:live={data.live} class="mode-notice">
	{#if data.live}<Sheet size={14}/><span><strong>{data.source === 'public' ? 'Live view-only Google Sheet' : 'Live Google Sheets'}</strong> — {data.source === 'public' ? 'showing real data from the shared sheet; editing and automatic sync require service-account credentials.' : 'showing synchronized spreadsheet data.'}</span>{:else}<CircleAlert size={14}/><span><strong>Demo data</strong> — the shared spreadsheet could not be read.</span>{/if}
</div>

<div class="sheet-tabs" role="tablist" aria-label="Google Sheets tables">
	{#each data.sheets as sheet}<button class:active={active === sheet.name} onclick={() => (active = sheet.name)}>{sheet.name}<span>{sheet.rows.length}</span></button>{/each}
</div>

<div class="table-summary"><div><span>Current table</span><h2>{selected.name}</h2></div><p><strong>{selected.rows.length}</strong> {selected.rows.length === 1 ? 'record' : 'records'} <i></i> Updated from the shared sheet</p></div>

<div class="card table-wrap sheet-table">
	<table class="data-table">
		<thead><tr>{#each selected.columns as column}<th class:phone-cell={isPhoneColumn(column)}>{column}</th>{/each}</tr></thead>
		<tbody>{#each selected.rows as row, rowIndex}<tr>{#each selected.columns as column, index}<td class:phone-cell={isPhoneColumn(column)}>{#if selected.links?.[rowIndex]?.[index]}<a class="cell-link" href={selected.links[rowIndex][index]} title={`Open related ${column.toLowerCase()}`}><span>{row[index] || '—'}</span><ArrowUpRight size={12}/></a>{:else}<span class:empty-value={!row[index]}>{row[index] || '—'}</span>{/if}</td>{/each}</tr>{:else}<tr><td class="empty-table" colspan={selected.columns.length}>No records are available in this table yet.</td></tr>{/each}</tbody>
	</table>
</div>

